function isHTMLTag(htmlString) {
    // 正则表达式匹配HTML标签
    const tagPattern = /<[^>]+>/g; // 匹配任何不包含闭合标签的标签
    // 使用test方法检查字符串是否匹配
    return tagPattern.test(htmlString);
}

