import deviceInfo from '@ohos.deviceInfo';

/**
 * 设置证书
 */
const setCertificate = (config: Record<string, Object>, options: Record<string, Object>): void => {
    // 设置caPath
    if (config.caPath) {
        options.caPath = config.caPath;
    }

    // 设置sslType
    if (config.sslType) {
        let apiVersion: number = deviceInfo.sdkApiVersion;
        if (config.sslType === 'TLCP' && apiVersion < 20) {
            throw new Error(`TLCP need Api >= 20,current api is ${apiVersion}`);
        }
        options.sslType = config.sslType;
    }

    // 设置客户端证书
    if (config.clientEncCert) {
        options.clientEncCert = config.clientEncCert;
        let { keyPasswd: keyPassword, ...rest } = options.clientEncCert as Record<string, Object>;
        let clientEncCert: Record<string, Object> = { ...rest, keyPassword };
        // certType转换为大小字符
        let certType: string = clientEncCert.certType as string;
        clientEncCert.certType = certType ? certType.toUpperCase() : certType;
        options.clientEncCert = clientEncCert;
    }

    // 设置客户端证书
    if (!utils.isUndefined(config.clientCert)) {
        options.clientCert = config.clientCert;
        // keyPasswd转换为keyPassword
        let { keyPasswd: keyPassword, ...rest } = options.clientCert as Record<string, Object>;
        let clientCert: Record<string, Object> = { ...rest, keyPassword };
        // certType转换为大小字符
        let certType: string = clientCert.certType as string;
        clientCert.certType = certType ? certType.toUpperCase() : certType;
        options.clientCert = clientCert;
    }
};

